import json
import time
from pathlib import Path
import anthropic

client = anthropic.Anthropic()
BATCH_SIZE = 10_000

def fan_out_process(items: list[dict], output_file: Path) -> dict:
    """Submit all items across multiple concurrent batches."""
    # Chunk into batches
    chunks = [items[i:i + BATCH_SIZE] for i in range(0, len(items), BATCH_SIZE)]

    # Submit all batches immediately (they run concurrently)
    batch_ids = []
    for chunk in chunks:
        requests = [
            {
                "custom_id": item["id"],
                "params": {
                    "model": "claude-haiku-4-5",
                    "max_tokens": 256,
                    "messages": [{"role": "user", "content": item["prompt"]}],
                },
            }
            for item in chunk
        ]
        batch = client.messages.batches.create(requests=requests)
        batch_ids.append(batch.id)
        print(f"Submitted batch {batch.id} ({len(chunk)} items)")

    # Persist IDs before waiting — crash safety
    Path("batch_ids.json").write_text(json.dumps(batch_ids))

    # Wait for all batches concurrently (poll all, process whichever finishes)
    pending = set(batch_ids)
    results: dict[str, str] = {}

    while pending:
        for batch_id in list(pending):
            batch = client.messages.batches.retrieve(batch_id)
            if batch.processing_status == "ended":
                for result in client.messages.batches.results(batch_id):
                    if result.result.type == "succeeded":
                        results[result.custom_id] = result.result.message.content[0].text
                pending.remove(batch_id)
                print(f"Batch {batch_id} complete ({len(results)} total results)")
        if pending:
            time.sleep(60)

    # Write merged results
    output_file.write_text(json.dumps(results, indent=2))
    return results

import time
import anthropic

client = anthropic.Anthropic()

def run_batch_and_collect(requests: list[dict]) -> dict[str, str]:
    """Submit a batch and return {custom_id: text} for all succeeded results."""
    batch = client.messages.batches.create(requests=requests)
    while True:
        b = client.messages.batches.retrieve(batch.id)
        if b.processing_status == "ended":
            break
        time.sleep(60)
    return {
        r.custom_id: r.result.message.content[0].text
        for r in client.messages.batches.results(batch.id)
        if r.result.type == "succeeded"
    }

def pipeline(documents: dict[str, str]) -> dict[str, str]:
    """Two-stage pipeline: extract entities → classify each entity."""

    # Stage 1: Extract named entities from each document
    stage1_requests = [
        {
            "custom_id": doc_id,
            "params": {
                "model": "claude-haiku-4-5",
                "max_tokens": 512,
                "messages": [{
                    "role": "user",
                    "content": f"List the named entities in this text as JSON:\n\n{text}",
                }],
            },
        }
        for doc_id, text in documents.items()
    ]
    print("Stage 1: extracting entities...")
    entity_results = run_batch_and_collect(stage1_requests)

    # Stage 2: Classify each entity list
    stage2_requests = [
        {
            "custom_id": f"{doc_id}_classified",
            "params": {
                "model": "claude-haiku-4-5",
                "max_tokens": 512,
                "messages": [{
                    "role": "user",
                    "content": f"Classify these entities by type (person/org/location):\n{entities}",
                }],
            },
        }
        for doc_id, entities in entity_results.items()
    ]
    print("Stage 2: classifying entities...")
    return run_batch_and_collect(stage2_requests)

import time
import anthropic

client = anthropic.Anthropic()

def map_reduce_summarize(documents: dict[str, str]) -> str:
    """Summarize each document (MAP), then produce a single global summary (REDUCE)."""

    # MAP: one batch request per document
    map_requests = [
        {
            "custom_id": doc_id,
            "params": {
                "model": "claude-haiku-4-5",
                "max_tokens": 200,
                "messages": [{
                    "role": "user",
                    "content": f"Summarize in 2 sentences:\n\n{text[:3000]}",
                }],
            },
        }
        for doc_id, text in documents.items()
    ]

    batch = client.messages.batches.create(requests=map_requests)
    while True:
        b = client.messages.batches.retrieve(batch.id)
        if b.processing_status == "ended":
            break
        time.sleep(60)

    summaries = [
        f"[{r.custom_id}]: {r.result.message.content[0].text}"
        for r in client.messages.batches.results(batch.id)
        if r.result.type == "succeeded"
    ]

    # REDUCE: single synchronous call (summaries are small enough)
    combined = "\n\n".join(summaries)
    reduce_response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        messages=[{
            "role": "user",
            "content": (
                f"You have {len(summaries)} document summaries below. "
                f"Write a single 3-paragraph executive summary of the entire corpus:\n\n{combined}"
            ),
        }],
    )
    return reduce_response.content[0].text

import json
import time
import statistics
import anthropic

client = anthropic.Anthropic()

def batch_eval(
    test_cases: list[dict],  # [{"id": ..., "prompt": ..., "reference": ...}]
    model_under_test: str = "claude-sonnet-4-6",
    judge_model: str = "claude-sonnet-4-6",
) -> dict:
    """Generate responses in batch, then judge them in a second batch."""

    # Step 1: Generate responses
    gen_requests = [
        {
            "custom_id": tc["id"],
            "params": {
                "model": model_under_test,
                "max_tokens": 512,
                "messages": [{"role": "user", "content": tc["prompt"]}],
            },
        }
        for tc in test_cases
    ]

    gen_batch = client.messages.batches.create(requests=gen_requests)
    while True:
        b = client.messages.batches.retrieve(gen_batch.id)
        if b.processing_status == "ended":
            break
        time.sleep(60)

    responses = {
        r.custom_id: r.result.message.content[0].text
        for r in client.messages.batches.results(gen_batch.id)
        if r.result.type == "succeeded"
    }

    # Step 2: Judge responses against reference answers
    ref_map = {tc["id"]: tc["reference"] for tc in test_cases}
    judge_requests = [
        {
            "custom_id": tc_id,
            "params": {
                "model": judge_model,
                "max_tokens": 64,
                "messages": [{
                    "role": "user",
                    "content": (
                        f"Rate this response 0-10 for correctness. "
                        f"Reference: {ref_map[tc_id]}\n"
                        f"Response: {response}\n"
                        f"Reply with just a number."
                    ),
                }],
            },
        }
        for tc_id, response in responses.items()
        if tc_id in ref_map
    ]

    judge_batch = client.messages.batches.create(requests=judge_requests)
    while True:
        b = client.messages.batches.retrieve(judge_batch.id)
        if b.processing_status == "ended":
            break
        time.sleep(60)

    scores = []
    for r in client.messages.batches.results(judge_batch.id):
        if r.result.type == "succeeded":
            try:
                score = float(r.result.message.content[0].text.strip())
                scores.append(score)
            except ValueError:
                pass

    return {
        "model": model_under_test,
        "n_cases": len(test_cases),
        "n_scored": len(scores),
        "mean_score": statistics.mean(scores) if scores else 0,
        "median_score": statistics.median(scores) if scores else 0,
    }

import json
import time
from pathlib import Path
import anthropic

client = anthropic.Anthropic()
STATE_FILE = Path("batch_state.json")

def load_state() -> dict:
    if STATE_FILE.exists():
        return json.loads(STATE_FILE.read_text())
    return {"batch_ids": [], "completed_ids": []}

def save_state(state: dict):
    STATE_FILE.write_text(json.dumps(state, indent=2))

def resumable_batch_run(requests: list[dict]) -> dict:
    state = load_state()

    # Submit only if no batch IDs saved yet (fresh run)
    if not state["batch_ids"]:
        batch = client.messages.batches.create(requests=requests)
        state["batch_ids"] = [batch.id]
        save_state(state)
        print(f"Submitted batch {batch.id}")
    else:
        print(f"Resuming with batch IDs: {state['batch_ids']}")

    results = {}
    pending = set(state["batch_ids"]) - set(state["completed_ids"])

    while pending:
        for batch_id in list(pending):
            b = client.messages.batches.retrieve(batch_id)
            if b.processing_status == "ended":
                for r in client.messages.batches.results(batch_id):
                    if r.result.type == "succeeded":
                        results[r.custom_id] = r.result.message.content[0].text
                state["completed_ids"].append(batch_id)
                save_state(state)
                pending.remove(batch_id)
                print(f"Batch {batch_id} done")
        if pending:
            time.sleep(60)

    STATE_FILE.unlink(missing_ok=True)  # clean up on success
    return results
